import sysfrom pathlib import Pathimport pandas as pdimport re# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import PROCESSED_DATA_DIR, INTERIM_DATA_DIR, TABLE_DIRdef split_into_sentences(text: str):    """    Simple sentence splitter for report snippets.    """    text = str(text).strip()    # split on punctuation followed by whitespace    sentences = re.split(r'(?<=[.!?])\s+', text)    sentences = [s.strip() for s in sentences if s.strip()]    return sentencesdef make_snippet(text: str, n_sentences: int = 4):    sents = split_into_sentences(text)    return " ".join(sents[:n_sentences])def main():    # 1. 读取已经聚合好的 document-level 数据（small_full）    doc_df = pd.read_parquet(PROCESSED_DATA_DIR / "train_doc_5d.parquet")    # 2. 从 sentence-level small_full 里补更多 metadata    sent_df = pd.read_parquet(INTERIM_DATA_DIR / "train_sent_small_full.parquet")    extra_meta_cols = [        "docID",        "tickers",        "exchanges",        "acceptanceDateTime",        "returns",    ]    extra_meta_cols = [c for c in extra_meta_cols if c in sent_df.columns]    extra_meta = (        sent_df[extra_meta_cols]        .drop_duplicates(subset=["docID"])        .copy()    )    merged = doc_df.merge(extra_meta, on="docID", how="left")    # 3. 生成 snippet（前4句，可改）    merged["snippet"] = merged["full_text"].apply(lambda x: make_snippet(x, n_sentences=4))    # 4. 选几个 example    # 方案A：一个正类，一个负类    pos_example = merged[merged["label_5d"] == 1].iloc[[0]].copy()    neg_example = merged[merged["label_5d"] == 0].iloc[[0]].copy()    example_df = pd.concat([pos_example, neg_example], axis=0)    # 5. 只保留你想展示的列    keep_cols = [        "docID",        "cik",        "filingDate",        "name",        "tickers",        "exchanges",        "entityType",        "sic",        "stateOfIncorporation",        "acceptanceDateTime",        "form",        "reportDate",        "label_5d",        "n_sentences",        "n_sections",        "snippet",    ]    keep_cols = [c for c in keep_cols if c in example_df.columns]    example_df = example_df[keep_cols].copy()    TABLE_DIR.mkdir(parents=True, exist_ok=True)    out_csv = TABLE_DIR / "report_document_examples_small_full.csv"    example_df.to_csv(out_csv, index=False)    print("Saved example file to:")    print(out_csv)    print("\nExample rows:")    print(example_df.to_string(index=False))if __name__ == "__main__":    main()    